import { render, screen, fireEvent, waitFor, act } from '@testing-library/react';
import '@testing-library/jest-dom';
import React from 'react';

let fetchMock: jest.Mock;

beforeEach(() => {
  jest.useFakeTimers();
  fetchMock = jest.fn();
  global.fetch = fetchMock;
});

afterEach(() => {
  jest.useRealTimers();
  jest.restoreAllMocks();
});

import App from './App';

describe('Retry with Exponential Backoff', () => {
  it('shows fetch button initially', () => {
    render(<App />);
    expect(screen.getByTestId('fetch-btn')).toBeInTheDocument();
    expect(screen.getByTestId('status-text')).toHaveTextContent('Ready to fetch');
  });

  it('fetches on button click', async () => {
    fetchMock.mockResolvedValueOnce({ ok: true, json: () => Promise.resolve({ value: 42 }) });
    render(<App />);
    await act(async () => {
      fireEvent.click(screen.getByTestId('fetch-btn'));
    });
    await waitFor(() => {
      expect(fetchMock).toHaveBeenCalledTimes(1);
    });
  });

  it('shows success on good response', async () => {
    fetchMock.mockResolvedValueOnce({ ok: true, json: () => Promise.resolve({ value: 42 }) });
    render(<App />);
    await act(async () => {
      fireEvent.click(screen.getByTestId('fetch-btn'));
    });
    await waitFor(() => {
      expect(screen.getByTestId('status-text')).toHaveTextContent('Success');
      expect(screen.getByTestId('data-display')).toBeInTheDocument();
    });
  });

  it('records timeline entry on success', async () => {
    fetchMock.mockResolvedValueOnce({ ok: true, json: () => Promise.resolve({ value: 42 }) });
    render(<App />);
    await act(async () => {
      fireEvent.click(screen.getByTestId('fetch-btn'));
    });
    await waitFor(() => {
      expect(screen.getByTestId('timeline-0')).toBeInTheDocument();
    });
  });

  it('retries on failure and shows attempt info', async () => {
    fetchMock.mockRejectedValueOnce(new Error('fail'));
    fetchMock.mockResolvedValueOnce({ ok: true, json: () => Promise.resolve({ value: 42 }) });
    render(<App />);
    await act(async () => {
      fireEvent.click(screen.getByTestId('fetch-btn'));
    });
    // First attempt fails
    await waitFor(() => {
      expect(screen.getByTestId('timeline-0')).toBeInTheDocument();
    });
    // Advance past backoff delay
    await act(async () => {
      jest.advanceTimersByTime(5000);
    });
    // Second attempt succeeds
    await waitFor(() => {
      expect(screen.getByTestId('status-text')).toHaveTextContent('Success');
    });
  });

  it('shows cancel button during fetch', async () => {
    fetchMock.mockReturnValue(new Promise(() => {})); // never resolves
    render(<App />);
    fireEvent.click(screen.getByTestId('fetch-btn'));
    await waitFor(() => {
      expect(screen.getByTestId('cancel-btn')).toBeInTheDocument();
    });
  });

  it('shows failed state when all retries exhausted', async () => {
    fetchMock.mockRejectedValue(new Error('fail'));
    render(<App />);
    await act(async () => {
      fireEvent.click(screen.getByTestId('fetch-btn'));
    });
    // Advance through all retries
    for (let i = 0; i < 3; i++) {
      await act(async () => {
        jest.advanceTimersByTime(10000);
      });
    }
    await waitFor(() => {
      expect(screen.getByTestId('status-text')).toHaveTextContent('exhausted');
    });
  });
});

