import React, { useState, useRef, useCallback } from 'react';
import './styles.css';

interface TimelineEntry {
  attempt: number;
  timestamp: string;
  status: 'pending' | 'success' | 'error';
  message: string;
}

interface RetryFetcherProps {
  apiUrl: string;
  maxRetries: number;
  baseDelay: number;
}

export const RetryFetcher: React.FC<RetryFetcherProps> = ({ apiUrl, maxRetries, baseDelay }) => {
  const [status, setStatus] = useState<'idle' | 'fetching' | 'retrying' | 'success' | 'failed'>('idle');
  const [data, setData] = useState<any>(null);
  const [timeline, setTimeline] = useState<TimelineEntry[]>([]);
  const [attempt, setAttempt] = useState(0);
  const [countdown, setCountdown] = useState(0);
  const abortRef = useRef<AbortController | null>(null);
  const timerRef = useRef<number | null>(null);
  const countdownRef = useRef<number | null>(null);

  const addEntry = useCallback((entry: TimelineEntry) => {
    setTimeline(prev => [...prev, entry]);
  }, []);

  const sleep = useCallback((ms: number, signal: AbortSignal): Promise<void> => {
    return new Promise((resolve, reject) => {
      const totalSec = Math.ceil(ms / 1000);
      let remaining = totalSec;
      setCountdown(remaining);

      countdownRef.current = window.setInterval(() => {
        remaining--;
        setCountdown(Math.max(0, remaining));
      }, 1000);

      timerRef.current = window.setTimeout(() => {
        if (countdownRef.current) clearInterval(countdownRef.current);
        setCountdown(0);
        resolve();
      }, ms);

      signal.addEventListener('abort', () => {
        if (timerRef.current) clearTimeout(timerRef.current);
        if (countdownRef.current) clearInterval(countdownRef.current);
        reject(new DOMException('Aborted', 'AbortError'));
      });
    });
  }, []);

  const startFetch = useCallback(async () => {
    const controller = new AbortController();
    abortRef.current = controller;
    setData(null);
    setTimeline([]);

    const totalAttempts = maxRetries + 1;

    for (let i = 1; i <= totalAttempts; i++) {
      if (controller.signal.aborted) return;

      setAttempt(i);
      setStatus('fetching');

      const ts = new Date().toLocaleTimeString();

      try {
        const res = await fetch(apiUrl, { signal: controller.signal });
        if (!res.ok) throw new Error(`HTTP ${res.status}`);
        const json = await res.json();

        addEntry({ attempt: i, timestamp: ts, status: 'success', message: 'Success' });
        setData(json);
        setStatus('success');
        return;
      } catch (err: any) {
        if (err.name === 'AbortError') {
          addEntry({ attempt: i, timestamp: ts, status: 'error', message: 'Cancelled' });
          setStatus('idle');
          return;
        }

        addEntry({ attempt: i, timestamp: ts, status: 'error', message: err.message || 'Error' });

        if (i < totalAttempts) {
          const delay = baseDelay * Math.pow(2, i - 1);
          const jitter = delay * (0.75 + Math.random() * 0.5);
          setStatus('retrying');
          try {
            await sleep(jitter, controller.signal);
          } catch {
            setStatus('idle');
            return;
          }
        }
      }
    }

    setStatus('failed');
  }, [apiUrl, maxRetries, baseDelay, addEntry, sleep]);

  const cancel = useCallback(() => {
    abortRef.current?.abort();
    setStatus('idle');
    setCountdown(0);
  }, []);

  const startOver = useCallback(() => {
    setStatus('idle');
    setData(null);
    setTimeline([]);
    setAttempt(0);
    setCountdown(0);
  }, []);

  return (
    <div className="rfetch">
      <div className="rfetch__controls">
        {status === 'idle' && (
          <button data-testid="fetch-btn" className="rfetch__btn rfetch__btn--primary" onClick={startFetch}>
            Fetch Data
          </button>
        )}
        {(status === 'fetching' || status === 'retrying') && (
          <button data-testid="cancel-btn" className="rfetch__btn rfetch__btn--danger" onClick={cancel}>
            Cancel
          </button>
        )}
        {status === 'failed' && (
          <button data-testid="start-over-btn" className="rfetch__btn rfetch__btn--primary" onClick={startOver}>
            Start Over
          </button>
        )}
      </div>

      <div data-testid="status-text" className="rfetch__status">
        {status === 'idle' && 'Ready to fetch'}
        {status === 'fetching' && 'Fetching…'}
        {status === 'retrying' && 'Waiting to retry…'}
        {status === 'success' && 'Success!'}
        {status === 'failed' && 'All retries exhausted'}
      </div>

      {(status === 'fetching' || status === 'retrying') && attempt > 0 && (
        <div data-testid="attempt-info" className="rfetch__attempt">
          Attempt {attempt} of {maxRetries + 1}
        </div>
      )}

      {status === 'retrying' && countdown > 0 && (
        <div data-testid="countdown" className="rfetch__countdown">
          Retrying in {countdown}s…
        </div>
      )}

      {data && (
        <pre data-testid="data-display" className="rfetch__data">
          {JSON.stringify(data, null, 2)}
        </pre>
      )}

      {timeline.length > 0 && (
        <div data-testid="timeline" className="rfetch__timeline">
          <h3>Request Timeline</h3>
          {timeline.map((entry, i) => (
            <div key={i} data-testid={`timeline-${i}`} className={`rfetch__entry rfetch__entry--${entry.status}`}>
              <span className="rfetch__ts">{entry.timestamp}</span>
              <span>Attempt {entry.attempt}: {entry.message}</span>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};
